sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {
	var requestBody = request.body;
	var metaDataString = requestBody;
	var objMetaData = JSON.parse(requestBody.dataString);

	var responseObj = copyTemplateTask(objMetaData);

	function copyTemplateTask(metaData){
		var apiTaskerTemplate = new api_tasker_template();
		var templateTaskCopied=false;
		var validMetaData = apiTaskerTemplate.validateMetaData("template_api.copyTaskTemplate", metaData);
		if(validMetaData.validCallData){
			templateTaskCopied= apiTaskerTemplate.copyTemplateTask(validMetaData.objId, validMetaData.newParentId);
			metaData.success = templateTaskCopied;
		}  // note, if invalid call data, success is set to false inside metadata check
		return metaData;
	}
})(request, response);
